func buildVocabMatchers(allChunks []DocumentChunk, useSchemaVocab bool, vocabEntities []map[string]interface{}) (*SchemaMatcher, *VocabularyMatcher, error) {
	if !useSchemaVocab && len(vocabEntities) == 0 {
		return nil, nil, nil
	}

	builder := NewSchemaVocabBuilder()
	if useSchemaVocab {
		if err := builder.AddChunks(allChunks); err != nil {
			return nil, nil, fmt.Errorf("buildVocabMatchers: add_chunks: %w", err)
		}
	}
	for _, entry := range vocabEntities {
		etype := "term"
		if v, ok := entry["entity_type"].(string); ok && v != "" {
			etype = v
		}
		entryType, _ := entry["type"].(string)
		if entryType == "static" {
			var names []string
			if ns, ok := entry["names"].([]interface{}); ok {
				for _, n := range ns {
					if s, ok := n.(string); ok {
						names = append(names, s)
					}
				}
			}
			builder.AddEntities(names, etype)
		} else if entryType == "db_query" {
			conn, _ := entry["connection"].(string)
			sqlStr, _ := entry["sql"].(string)
			if err := builder.AddFromDB(conn, map[string]string{etype: sqlStr}); err != nil {
				return nil, nil, fmt.Errorf("buildVocabMatchers: add_from_db: %w", err)
			}
		}
	}
	schemaMatcher, err := builder.Build()
	if err != nil {
		return nil, nil, fmt.Errorf("buildVocabMatchers: build: %w", err)
	}
	var dataMatcher *VocabularyMatcher
	if builder.DataTermCount() > 0 {
		dm, err := builder.BuildDataMatcher()
		if err != nil {
			return nil, nil, fmt.Errorf("buildVocabMatchers: build_data_matcher: %w", err)
		}
		dataMatcher = dm
	}
	return schemaMatcher, dataMatcher, nil
}

