	Chunk DocumentChunk
}

func collectChunksToProcess(allChunks []DocumentChunk, skipIDs map[string]struct{}) []ChunkWithID {
	var result []ChunkWithID
	for _, c := range allChunks {
		embedContent := c.EmbeddingContent
		if len(embedContent) == 0 {
			embedContent = c.Content
		}
		cid := generateChunkID(c.DocumentName, c.ChunkIndex, embedContent)
		if _, skip := skipIDs[cid]; !skip {
			result = append(result, ChunkWithID{ID: cid, Chunk: c})
		}
	}
	return result
}

