type EntityMeta struct {
	Name        string
	DisplayName string
	EntityType  string
}

func runNEROnChunks(
	chunksToProcess []ChunkWithID,
	matcher Matcher,
	schemaMatcher Matcher,
	dataMatcher Matcher,
) (*EntityIndex, map[string]EntityMeta, error) {
	entityIndex := NewEntityIndex()
	entityMeta := make(map[string]EntityMeta)

	for _, item := range chunksToProcess {
		chunkID := item.ID
		chunk := item.Chunk
		if schemaMatcher != nil || dataMatcher != nil {
			var vocabHits []EntityMatch
			if schemaMatcher != nil {
				merged, err := mergeMatches(schemaMatcher.Match(chunk.Content), vocabHits, chunk.Content, true)
				if err != nil {
					return nil, nil, fmt.Errorf("runNEROnChunks: schema merge: %w", err)
				}
				vocabHits = merged
			}
			if dataMatcher != nil {
				merged, err := mergeMatches(dataMatcher.Match(chunk.Content), vocabHits, chunk.Content, true)
				if err != nil {
					return nil, nil, fmt.Errorf("runNEROnChunks: data merge: %w", err)
				}
				vocabHits = merged
			}
			combined, err := mergeMatches(vocabHits, matcher.Match(chunk.Content), chunk.Content, true)
			if err != nil {
				return nil, nil, fmt.Errorf("runNEROnChunks: combined merge: %w", err)
			}
			for _, m := range combined {
				if _, exists := entityMeta[m.EntityID]; !exists {
					et := m.EntityType
					if et == "" {
						et = "concept"
					}
					entityMeta[m.EntityID] = EntityMeta{Name: m.Name, DisplayName: m.DisplayName, EntityType: et}
				}
			}
			entityIndex.IndexChunk(chunkID, chunk.Content, combined)
		} else {
			matches := matcher.Match(chunk.Content)
			for _, m := range matches {
				if _, exists := entityMeta[m.EntityID]; !exists {
					et := m.EntityType
					if et == "" {
						et = "concept"
					}
					entityMeta[m.EntityID] = EntityMeta{Name: m.Name, DisplayName: m.DisplayName, EntityType: et}
				}
			}
			entityIndex.IndexChunk(chunkID, chunk.Content, matches)
		}
	}

	entityIndex.RecomputeScores()
	return entityIndex, entityMeta, nil
}

