func persistAssociations(con *sql.DB, data map[string]interface{}, entityMeta map[string]EntityMeta, incremental bool) error {
	if !incremental {
		if _, err := con.Exec("DELETE FROM chunk_entities"); err != nil {
			return fmt.Errorf("persistAssociations: delete chunk_entities: %w", err)
		}
		if _, err := con.Exec("DELETE FROM entities"); err != nil {
			return fmt.Errorf("persistAssociations: delete entities: %w", err)
		}
	}

	associations, _ := data["associations"].([]map[string]interface{})
	for _, a := range associations {
		chunkID, _ := a["chunk_id"].(string)
		entityID, _ := a["entity_id"].(string)
		frequency, _ := a["frequency"].(int)
		score, _ := a["score"].(float64)
		positions, _ := a["positions"].([]int)

		var chunkNamespace *string
		row := con.QueryRow("SELECT namespace FROM embeddings WHERE chunk_id = ?", chunkID)
		var ns string
		if err := row.Scan(&ns); err == nil {
			chunkNamespace = &ns
		}

		posJSON, err := json.Marshal(positions)
		if err != nil {
			return fmt.Errorf("persistAssociations: marshal positions: %w", err)
		}
		if _, err := con.Exec(
			"INSERT OR REPLACE INTO chunk_entities(chunk_id, entity_id, frequency, positions_json, score, namespace) VALUES (?,?,?,?,?,?)",
			chunkID, entityID, frequency, string(posJSON), score, chunkNamespace,
		); err != nil {
			return fmt.Errorf("persistAssociations: insert chunk_entities: %w", err)
		}

		meta, ok := entityMeta[entityID]
		if !ok {
			meta = EntityMeta{Name: entityID, DisplayName: entityID, EntityType: "concept"}
		}
		if _, err := con.Exec(
			"INSERT OR IGNORE INTO entities(id, name, display_name, entity_type) VALUES (?,?,?,?)",
			entityID, meta.Name, meta.DisplayName, meta.EntityType,
		); err != nil {
			return fmt.Errorf("persistAssociations: insert entities: %w", err)
		}

		alias := stripIDAliasFunc(entityID)
		if len(alias) > 0 {
			if _, err := con.Exec(
				"INSERT OR IGNORE INTO entity_aliases(alias, entity_id, source) VALUES (?,?,?)",
				alias, entityID, "strip_suffix",
			); err != nil {
				return fmt.Errorf("persistAssociations: insert entity_aliases: %w", err)
			}
		}
	}
	return nil
}

type BuildNEROptions struct {
	SpacyModel        string
	UseSchemaVocab    bool
	VocabEntities     []map[string]interface{}
	Force             bool
	BuildContextGraph bool
	Namespace         string
}

func BuildNER(store *Store, opts BuildNEROptions) (int, error) {
	if opts.SpacyModel == "" {
		opts.SpacyModel = defaultSpacyModel
	}
	if opts.Namespace == "" {
		opts.Namespace = "global"
	}

	con := store.Vector.Conn()
	if _, err := con.Exec(nerCacheDDL); err != nil {
		return 0, fmt.Errorf("BuildNER: create ner_cache: %w", err)
	}

	fingerprint, err := nerConfigFingerprint(opts.SpacyModel, opts.UseSchemaVocab, opts.VocabEntities)
	if err != nil {
		return 0, fmt.Errorf("BuildNER: fingerprint: %w", err)
	}

	shouldReturnEarly, incremental, skipIDs, err := checkCache(con, fingerprint, opts.Force)
	if err != nil {
		return 0, fmt.Errorf("BuildNER: check_cache: %w", err)
	}
	if shouldReturnEarly {
		var count int
		if err := con.QueryRow("SELECT COUNT(*) FROM chunk_entities").Scan(&count); err != nil {
			return 0, fmt.Errorf("BuildNER: count chunk_entities: %w", err)
		}
		return count, nil
	}

	var labelTypes []SpacyLabel
	for _, t := range allSpacyLabels() {
		if !isNumericType(t) {
			labelTypes = append(labelTypes, t)
		}
	}
	matcher := NewSpacyMatcher(opts.SpacyModel, true, labelTypes)

	allChunks, err := store.Vector.GetAllChunks()
	if err != nil {
		return 0, fmt.Errorf("BuildNER: get_all_chunks: %w", err)
	}
	schemaMatcher, dataMatcher, err := buildVocabMatchers(allChunks, opts.UseSchemaVocab, opts.VocabEntities)
	if err != nil {
		return 0, fmt.Errorf("BuildNER: build_vocab_matchers: %w", err)
	}
	chunksToProcess := collectChunksToProcess(allChunks, skipIDs)

	entityIndex, entityMeta, err := runNEROnChunks(chunksToProcess, matcher, schemaMatcher, dataMatcher)
	if err != nil {
		return 0, fmt.Errorf("BuildNER: run_ner_on_chunks: %w", err)
	}

	data := entityIndex.ToDict()
	if err := persistAssociations(con, data, entityMeta, incremental); err != nil {
		return 0, fmt.Errorf("BuildNER: persist_associations: %w", err)
	}

	allChunkCount, err := allChunkIDCount(con)
	if err != nil {
		return 0, fmt.Errorf("BuildNER: all_chunk_count: %w", err)
	}
	if _, err := con.Exec(
		"INSERT OR REPLACE INTO ner_cache(config_fingerprint, chunk_count) VALUES (?, ?)",
		fingerprint, allChunkCount,
	); err != nil {
		return 0, fmt.Errorf("BuildNER: upsert ner_cache: %w", err)
	}

	if opts.BuildContextGraph {
		if err := buildContextGraphEdges(con, opts.Namespace, true); err != nil {
			return 0, fmt.Errorf("BuildNER: build_context_graph: %w", err)
		}
	}

	assocs, _ := data["associations"].([]map[string]interface{})
	return len(assocs), nil
}

