func (p *NerPipeline) Match(text string) ([]EntityMatch, error) {
	var vocabHits []EntityMatch

	if p.dbEnrich {
		sm, err := p.getSchemaMatcherLazy()
		if err != nil {
			return nil, fmt.Errorf("NerPipeline.Match: get_schema_matcher: %w", err)
		}
		vocabHits = append(vocabHits, sm.Match(text)...)
	}

	if p.builder.DataTermCount() > 0 {
		dm, err := p.getDataMatcherLazy()
		if err != nil {
			return nil, fmt.Errorf("NerPipeline.Match: get_data_matcher: %w", err)
		}
		vocabHits = append(vocabHits, dm.Match(text)...)
	}

	var spacyHits []EntityMatch
	if p.spacyEntities {
		spm, err := p.getSpacyMatcherLazy()
		if err != nil {
			return nil, fmt.Errorf("NerPipeline.Match: get_spacy_matcher: %w", err)
		}
		spacyHits = spm.Match(text)
	}

	if len(vocabHits) > 0 && len(spacyHits) > 0 {
		return mergeMatches(vocabHits, spacyHits, text, true)
	}
	if len(vocabHits) > 0 {
		return vocabHits, nil
	}
	return spacyHits, nil
}

