func (p *NerPipeline) RunOnChunks(chunks []DocumentChunk, entityIndex *EntityIndex, chunkIDs []string) (map[string][]EntityMatch, error) {
	results := make(map[string][]EntityMatch)
	for i, chunk := range chunks {
		var cid string
		if chunkIDs != nil {
			cid = chunkIDs[i]
		} else {
			cid = fmt.Sprintf("%s:%d", chunk.DocumentName, chunk.ChunkIndex)
		}
		content := chunk.Content
		if len(content) == 0 {
			content = ""
		}
		matches, err := p.Match(content)
		if err != nil {
			return nil, fmt.Errorf("NerPipeline.RunOnChunks: match chunk %s: %w", cid, err)
		}
		if len(matches) > 0 {
			entityIndex.IndexChunk(cid, content, matches)
			results[cid] = matches
		}
	}
	return results, nil
}

