func mergeMatches(vocabMatches []EntityMatch, genericMatches []EntityMatch, sourceText string, boundaryStrip bool) ([]EntityMatch, error) {
	var vocabSpanSet [][2]int
	for _, m := range vocabMatches {
		vocabSpanSet = append(vocabSpanSet, m.Spans...)
	}

	var survivingGeneric []EntityMatch
	for _, gm := range genericMatches {
		var keptSpans [][2]int
		for _, span := range gm.Spans {
			if boundaryStrip && len(sourceText) > 0 {
				stripped, ok := stripSpan(sourceText, span[0], span[1])
				if !ok {
					continue
				}
				span = stripped
			}
			overlaps := false
			for _, vs := range vocabSpanSet {
				if overlapsSpans(span, vs) {
					overlaps = true
					break
				}
			}
			if !overlaps {
				keptSpans = append(keptSpans, span)
			}
		}
		if len(keptSpans) > 0 {
			var positions []int
			for _, s := range keptSpans {
				positions = append(positions, s[0])
			}
			survivingGeneric = append(survivingGeneric, EntityMatch{
				EntityID:    gm.EntityID,
				Name:        gm.Name,
				DisplayName: gm.DisplayName,
				EntityType:  gm.EntityType,
				Frequency:   len(keptSpans),
				Positions:   positions,
				Spans:       keptSpans,
			})
		}
	}

	merged := make(map[string]EntityMatch)
	allMatches := append(vocabMatches, survivingGeneric...)
	for _, m := range allMatches {
		if _, exists := merged[m.EntityID]; !exists {
			merged[m.EntityID] = EntityMatch{
