func stripSpan(text string, start, end int) ([2]int, bool) {
	runes := []rune(text)
	if start < 0 || end > len(runes) || start >= end {
		return [2]int{}, false
	}

	// Strip from left
	newStart := start
	for newStart < end {
		ch := runes[newStart]
		if isBoundaryChar(ch) || unicode.IsSpace(ch) {
			newStart++
		} else {
			break
		}
	}

	// Strip from right
	newEnd := end
	for newEnd > newStart {
		ch := runes[newEnd-1]
		if isBoundaryChar(ch) || unicode.IsSpace(ch) {
			newEnd--
		} else {
			break
		}
	}

	if newEnd <= newStart {
		return [2]int{}, false
	}
	return [2]int{newStart, newEnd}, true
}

