var (
	leadingTrailingSymbols = regexp.MustCompile(`^[^\w\s]+|[^\w\s]+$`)
	multiSpace            = regexp.MustCompile(`\s+`)
	dottedAcronym         = regexp.MustCompile(`^([A-Z0-9]\.){2,}[A-Z0-9]?\.?$`)
	removeDots            = regexp.MustCompile(`\.`)
)

func NormalizeEntity(entity string) string {
	if len(entity) == 0 {
		return ""
	}

	// 1. Strip whitespace
	entity = strings.TrimSpace(entity)

	// 2. Strip leading/trailing non-word/non-space characters
	entity = strings.TrimSpace(leadingTrailingSymbols.ReplaceAllString(entity, ""))

	// 3. Collapse dotted acronyms: U.S.A. -> USA
	tokParts := strings.Split(entity, " ")
	var processedToks []string
	for _, tok := range tokParts {
		suffix := "."
		if strings.HasSuffix(tok, ".") {
			suffix = ""
		}
		if dottedAcronym.MatchString(tok + suffix) {
			tok = removeDots.ReplaceAllString(tok, "")
		}
		processedToks = append(processedToks, tok)
	}
	entity = strings.Join(processedToks, " ")

	// 4. Collapse internal whitespace
	entity = multiSpace.ReplaceAllString(entity, " ")

	if len(entity) == 0 {
		return ""
	}

	// 5. Split, singularize last token, rejoin
	tokens, sep := splitTokens(entity)
	var filtered []string
	for _, t := range tokens {
		if len(t) > 0 {
			filtered = append(filtered, t)
		}
	}
	if len(filtered) == 0 {
		return ""
	}
	filtered[len(filtered)-1] = singularize(filtered[len(filtered)-1])
	return strings.Join(filtered, sep)
}

