// (?<=[a-z0-9])(?=[A-Z])|(?<=[A-Z])(?=[A-Z][a-z]). Approximate split used below.
var camelBoundaryApprox = regexp.MustCompile(`([a-z0-9])([A-Z])|([A-Z]+)([A-Z][a-z])`)

func splitTokens(text string) ([]string, string) {
	if strings.Contains(text, " ") {
		return strings.Split(text, " "), " "
	}
	if strings.Contains(text, "_") {
		return strings.Split(text, "_"), "_"
	}
	// Approximate CamelCase split using RE2-compatible pattern
	expanded := camelBoundaryApprox.ReplaceAllString(text, "${1}${3} ${2}${4}")
	expanded = strings.TrimSpace(expanded)
	parts := strings.Fields(expanded)
	if len(parts) > 1 {
		return parts, ""
	}
	return []string{text}, ""
}
